package com.weeklycommit.rcdo.controller;

import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.RcdoValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

@RestControllerAdvice
public class GlobalExceptionHandler {

	@ExceptionHandler(RcdoValidationException.class)
	public ResponseEntity<Map<String, Object>> handleRcdoValidation(RcdoValidationException ex) {
		return ResponseEntity.badRequest().body(errorBody(ex.getMessage()));
	}

	@ExceptionHandler(PlanValidationException.class)
	public ResponseEntity<Map<String, Object>> handlePlanValidation(PlanValidationException ex) {
		return ResponseEntity.badRequest().body(errorBody(ex.getMessage()));
	}

	@ExceptionHandler(ResourceNotFoundException.class)
	public ResponseEntity<Map<String, Object>> handleNotFound(ResourceNotFoundException ex) {
		return ResponseEntity.status(HttpStatus.NOT_FOUND).body(errorBody(ex.getMessage()));
	}

	@ExceptionHandler(MethodArgumentNotValidException.class)
	public ResponseEntity<Map<String, Object>> handleBeanValidation(MethodArgumentNotValidException ex) {
		String details = ex.getBindingResult().getFieldErrors().stream()
				.map(fe -> fe.getField() + ": " + fe.getDefaultMessage()).collect(Collectors.joining("; "));
		return ResponseEntity.badRequest().body(errorBody(details));
	}

	private static Map<String, Object> errorBody(String message) {
		Map<String, Object> body = new LinkedHashMap<>();
		body.put("error", message);
		return body;
	}
}

package com.weeklycommit.plan.controller;

import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.CreateCommitRequest;
import com.weeklycommit.plan.dto.CreatePlanRequest;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.dto.ReorderCommitsRequest;
import com.weeklycommit.plan.dto.UpdateCommitRequest;
import com.weeklycommit.plan.service.CommitService;
import com.weeklycommit.plan.service.WeeklyPlanService;
import jakarta.validation.Valid;
import java.util.List;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/plans")
public class PlanController {

	private final WeeklyPlanService planService;
	private final CommitService commitService;

	public PlanController(WeeklyPlanService planService, CommitService commitService) {
		this.planService = planService;
		this.commitService = commitService;
	}

	/** List all plans for a user in descending week order. */
	@GetMapping
	public ResponseEntity<List<PlanResponse>> listPlans(@RequestParam UUID userId) {
		return ResponseEntity.ok(planService.listPlansForUser(userId));
	}

	/**
	 * Get-or-create the plan for a user + week. If {@code weekStartDate} is omitted
	 * the current week's Monday is used.
	 */
	@PostMapping
	public ResponseEntity<PlanWithCommitsResponse> getOrCreatePlan(@Valid @RequestBody CreatePlanRequest request) {
		java.time.LocalDate weekStart = request.weekStartDate() != null
				? request.weekStartDate()
				: WeeklyPlanService.currentWeekStart();
		WeeklyPlan plan = planService.getOrCreatePlan(request.userId(), weekStart);
		return ResponseEntity.status(HttpStatus.OK).body(planService.getPlanWithCommits(plan.getId()));
	}

	/** Plan detail with commits in priority order. */
	@GetMapping("/{id}")
	public ResponseEntity<PlanWithCommitsResponse> getPlan(@PathVariable UUID id) {
		return ResponseEntity.ok(planService.getPlanWithCommits(id));
	}

	/** Create a commit on a DRAFT plan. */
	@PostMapping("/{planId}/commits")
	public ResponseEntity<CommitResponse> createCommit(@PathVariable UUID planId,
			@Valid @RequestBody CreateCommitRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		WeeklyCommit commit = commitService.createCommit(planId, request, actorUserId);
		return ResponseEntity.status(HttpStatus.CREATED).body(CommitResponse.from(commit));
	}

	/** Update mutable commit fields. Null fields are ignored (partial update). */
	@PutMapping("/{planId}/commits/{commitId}")
	public ResponseEntity<CommitResponse> updateCommit(@PathVariable UUID planId, @PathVariable UUID commitId,
			@RequestBody UpdateCommitRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		WeeklyCommit commit = commitService.updateCommit(commitId, request, actorUserId);
		return ResponseEntity.ok(CommitResponse.from(commit));
	}

	/** Delete a commit and re-number the remaining ones. */
	@DeleteMapping("/{planId}/commits/{commitId}")
	public ResponseEntity<Void> deleteCommit(@PathVariable UUID planId, @PathVariable UUID commitId,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		commitService.deleteCommit(commitId, actorUserId);
		return ResponseEntity.noContent().build();
	}

	/** Reorder commits by supplying all commit IDs in the desired order. */
	@PutMapping("/{planId}/commits/reorder")
	public ResponseEntity<PlanWithCommitsResponse> reorderCommits(@PathVariable UUID planId,
			@Valid @RequestBody ReorderCommitsRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		commitService.reorderCommits(planId, request.commitIds(), actorUserId);
		return ResponseEntity.ok(planService.getPlanWithCommits(planId));
	}
}

package com.weeklycommit.plan.service;

import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.ZoneOffset;
import java.time.temporal.TemporalAdjusters;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class WeeklyPlanService {

	private final WeeklyPlanRepository planRepo;
	private final UserAccountRepository userRepo;
	private final WeeklyCommitRepository commitRepo;

	public WeeklyPlanService(WeeklyPlanRepository planRepo, UserAccountRepository userRepo,
			WeeklyCommitRepository commitRepo) {
		this.planRepo = planRepo;
		this.userRepo = userRepo;
		this.commitRepo = commitRepo;
	}

	// -------------------------------------------------------------------------
	// Public API
	// -------------------------------------------------------------------------

	/**
	 * Returns the existing DRAFT plan for the given user+week, or lazily creates
	 * one. Enforces the one-plan-per-user-per-week invariant via the unique
	 * constraint in the database; the in-memory check here is an early guard.
	 */
	public WeeklyPlan getOrCreatePlan(UUID userId, LocalDate weekStartDate) {
		return planRepo.findByOwnerUserIdAndWeekStartDate(userId, weekStartDate)
				.orElseGet(() -> createDraftPlan(userId, weekStartDate));
	}

	/**
	 * Convenience: resolve the current week's Monday and delegate to getOrCreate.
	 */
	public WeeklyPlan getMyCurrentWeekPlan(UUID userId) {
		return getOrCreatePlan(userId, currentWeekStart());
	}

	/** Returns the plan with its commits ordered by priority. */
	@Transactional(readOnly = true)
	public PlanWithCommitsResponse getPlanWithCommits(UUID planId) {
		WeeklyPlan plan = findById(planId);
		return toResponse(plan);
	}

	/** Lists all plans for a user in descending week order. */
	@Transactional(readOnly = true)
	public List<PlanResponse> listPlansForUser(UUID userId) {
		return planRepo.findByOwnerUserIdOrderByWeekStartDateDesc(userId).stream().map(PlanResponse::from).toList();
	}

	/** Calculates the Monday of the current ISO week (UTC). */
	public static LocalDate currentWeekStart() {
		return LocalDate.now(ZoneOffset.UTC).with(TemporalAdjusters.previousOrSame(DayOfWeek.MONDAY));
	}

	// -------------------------------------------------------------------------
	// Internal helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan createDraftPlan(UUID userId, LocalDate weekStartDate) {
		UserAccount user = userRepo.findById(userId)
				.orElseThrow(() -> new ResourceNotFoundException("User not found: " + userId));

		if (user.getHomeTeamId() == null) {
			throw new PlanValidationException("User " + userId + " has no home team; cannot create a weekly plan");
		}

		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(userId);
		plan.setTeamId(user.getHomeTeamId());
		plan.setWeekStartDate(weekStartDate);
		plan.setState(PlanState.DRAFT);
		plan.setCapacityBudgetPoints(user.getWeeklyCapacityPoints());

		// Default cadence: lock by Monday noon, reconcile due next Monday 10:00 UTC
		plan.setLockDeadline(weekStartDate.atTime(12, 0).toInstant(ZoneOffset.UTC));
		plan.setReconcileDeadline(weekStartDate.plusDays(7).atTime(10, 0).toInstant(ZoneOffset.UTC));

		return planRepo.save(plan);
	}

	WeeklyPlan findById(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	PlanWithCommitsResponse toResponse(WeeklyPlan plan) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(plan.getId());
		int totalPoints = commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0)
				.sum();
		return new PlanWithCommitsResponse(PlanResponse.from(plan), commits.stream().map(CommitResponse::from).toList(),
				totalPoints);
	}
}

package com.weeklycommit.plan.service;

import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.plan.dto.CreateCommitRequest;
import com.weeklycommit.plan.dto.UpdateCommitRequest;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.rcdo.service.RcdoLinkageValidator;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class CommitService {

	/** Valid Fibonacci-scale estimate values. */
	private static final Set<Integer> VALID_ESTIMATE_POINTS = Set.of(1, 2, 3, 5, 8);

	private static final int MAX_KING_PER_WEEK = 1;
	private static final int MAX_QUEEN_PER_WEEK = 2;

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final WorkItemRepository workItemRepo;
	private final RcdoLinkageValidator rcdoLinkageValidator;

	public CommitService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			WorkItemRepository workItemRepo, RcdoLinkageValidator rcdoLinkageValidator) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.workItemRepo = workItemRepo;
		this.rcdoLinkageValidator = rcdoLinkageValidator;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	public WeeklyCommit createCommit(UUID planId, CreateCommitRequest req, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);
		validateDraftState(plan);

		// Validate chess piece limits
		validateChessPieceLimits(planId, req.chessPiece(), null);

		// Validate estimate points if provided
		validateEstimatePoints(req.estimatePoints());

		// Success criteria required for King / Queen
		validateSuccessCriteria(req.chessPiece(), req.successCriteria());

		// Resolve RCDO: use explicit value, else default from ticket
		UUID rcdoNodeId = resolveRcdoNodeId(req.rcdoNodeId(), req.workItemId());

		// Validate RCDO linkage if provided
		if (rcdoNodeId != null) {
			rcdoLinkageValidator.validateCommitLinkage(rcdoNodeId);
		}

		WeeklyCommit commit = new WeeklyCommit();
		commit.setPlanId(planId);
		commit.setOwnerUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		commit.setTitle(req.title());
		commit.setChessPiece(req.chessPiece());
		commit.setDescription(req.description());
		commit.setRcdoNodeId(rcdoNodeId);
		commit.setWorkItemId(req.workItemId());
		commit.setEstimatePoints(req.estimatePoints());
		commit.setSuccessCriteria(req.successCriteria());
		commit.setPriorityOrder(nextPriorityOrder(planId));

		return commitRepo.save(commit);
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	public WeeklyCommit updateCommit(UUID commitId, UpdateCommitRequest req, UUID actorUserId) {
		WeeklyCommit commit = findCommit(commitId);
		WeeklyPlan plan = findPlan(commit.getPlanId());
		validateDraftState(plan);

		// Effective values after applying patch
		ChessPiece effectivePiece = req.chessPiece() != null ? req.chessPiece() : commit.getChessPiece();
		String effectiveCriteria = req.successCriteria() != null ? req.successCriteria() : commit.getSuccessCriteria();
		Integer effectivePoints = req.estimatePoints() != null ? req.estimatePoints() : commit.getEstimatePoints();
		UUID effectiveRcdo = req.rcdoNodeId() != null ? req.rcdoNodeId() : commit.getRcdoNodeId();

		// If chess piece is changing, re-validate limits excluding this commit
		if (req.chessPiece() != null && req.chessPiece() != commit.getChessPiece()) {
			validateChessPieceLimits(commit.getPlanId(), req.chessPiece(), commitId);
		}

		validateEstimatePoints(effectivePoints);
		validateSuccessCriteria(effectivePiece, effectiveCriteria);

		if (effectiveRcdo != null && !effectiveRcdo.equals(commit.getRcdoNodeId())) {
			rcdoLinkageValidator.validateCommitLinkage(effectiveRcdo);
		}

		// Apply non-null fields
		if (req.title() != null && !req.title().isBlank()) {
			commit.setTitle(req.title());
		}
		if (req.chessPiece() != null) {
			commit.setChessPiece(req.chessPiece());
		}
		if (req.description() != null) {
			commit.setDescription(req.description());
		}
		if (req.rcdoNodeId() != null) {
			commit.setRcdoNodeId(req.rcdoNodeId());
		}
		if (req.workItemId() != null) {
			commit.setWorkItemId(req.workItemId());
		}
		if (req.estimatePoints() != null) {
			commit.setEstimatePoints(req.estimatePoints());
		}
		if (req.successCriteria() != null) {
			commit.setSuccessCriteria(req.successCriteria());
		}

		return commitRepo.save(commit);
	}

	// -------------------------------------------------------------------------
	// Delete
	// -------------------------------------------------------------------------

	public void deleteCommit(UUID commitId, UUID actorUserId) {
		WeeklyCommit commit = findCommit(commitId);
		WeeklyPlan plan = findPlan(commit.getPlanId());
		validateDraftState(plan);

		UUID planId = commit.getPlanId();
		commitRepo.delete(commit);

		// Re-number remaining commits sequentially
		List<WeeklyCommit> remaining = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		for (int i = 0; i < remaining.size(); i++) {
			remaining.get(i).setPriorityOrder(i + 1);
			commitRepo.save(remaining.get(i));
		}
	}

	// -------------------------------------------------------------------------
	// Reorder
	// -------------------------------------------------------------------------

	public List<WeeklyCommit> reorderCommits(UUID planId, List<UUID> orderedCommitIds, UUID actorUserId) {
		WeeklyPlan plan = findPlan(planId);
		validateDraftState(plan);

		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		Set<UUID> planIds = new HashSet<>();
		for (WeeklyCommit c : commits) {
			planIds.add(c.getId());
		}

		if (!planIds.equals(new HashSet<>(orderedCommitIds))) {
			throw new PlanValidationException("Reorder list must contain exactly all commit IDs for this plan");
		}

		for (int i = 0; i < orderedCommitIds.size(); i++) {
			final int newOrder = i + 1;
			UUID cId = orderedCommitIds.get(i);
			commits.stream().filter(c -> c.getId().equals(cId)).findFirst().ifPresent(c -> {
				c.setPriorityOrder(newOrder);
				commitRepo.save(c);
			});
		}

		return commitRepo.findByPlanIdOrderByPriorityOrder(planId);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	WeeklyCommit findCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private WeeklyPlan findPlan(UUID planId) {
		return planRepo.findById(planId)
				.orElseThrow(() -> new ResourceNotFoundException("Weekly plan not found: " + planId));
	}

	private void validateDraftState(WeeklyPlan plan) {
		if (plan.getState() != PlanState.DRAFT) {
			throw new PlanValidationException(
					"Plan " + plan.getId() + " is not in DRAFT state (current: " + plan.getState() + ")");
		}
	}

	void validateChessPieceLimits(UUID planId, ChessPiece piece, UUID excludeCommitId) {
		List<WeeklyCommit> commits = commitRepo.findByPlanIdOrderByPriorityOrder(planId);
		long count = commits.stream().filter(c -> excludeCommitId == null || !c.getId().equals(excludeCommitId))
				.filter(c -> c.getChessPiece() == piece).count();

		if (piece == ChessPiece.KING && count >= MAX_KING_PER_WEEK) {
			throw new PlanValidationException("Maximum " + MAX_KING_PER_WEEK + " King commit(s) per week exceeded");
		}
		if (piece == ChessPiece.QUEEN && count >= MAX_QUEEN_PER_WEEK) {
			throw new PlanValidationException("Maximum " + MAX_QUEEN_PER_WEEK + " Queen commit(s) per week exceeded");
		}
	}

	void validateEstimatePoints(Integer points) {
		if (points != null && !VALID_ESTIMATE_POINTS.contains(points)) {
			throw new PlanValidationException("Estimate points must be one of {1, 2, 3, 5, 8}, got: " + points);
		}
	}

	void validateSuccessCriteria(ChessPiece piece, String successCriteria) {
		if ((piece == ChessPiece.KING || piece == ChessPiece.QUEEN)
				&& (successCriteria == null || successCriteria.isBlank())) {
			throw new PlanValidationException("Success criteria is required for " + piece + " commits");
		}
	}

	private int nextPriorityOrder(UUID planId) {
		return (int) (commitRepo.countByPlanId(planId) + 1);
	}

	private UUID resolveRcdoNodeId(UUID requestedRcdo, UUID workItemId) {
		if (requestedRcdo != null) {
			return requestedRcdo;
		}
		if (workItemId != null) {
			return workItemRepo.findById(workItemId).map(WorkItem::getRcdoNodeId).orElse(null);
		}
		return null;
	}
}

